const input = $input.first().json;
const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.finnhub&cred_key=eq.finnhub_api_key&select=cred_value',
  headers: pgHeaders
});
if (!creds || !creds[0] || !creds[0].cred_value) {
  return [{ json: { error: 'Finnhub API key not configured. Use add_credential to set it up.' } }];
}
const token = creds[0].cred_value;
const API = 'https://finnhub.io/api/v1';

function formatCap(millions) {
  if (millions == null) return '';
  if (millions >= 1000000) return (millions / 1000000).toFixed(2) + 'T';
  if (millions >= 1000) return (millions / 1000).toFixed(2) + 'B';
  return millions.toFixed(2) + 'M';
}

function formatTs(unix) {
  if (!unix) return '';
  return new Date(unix * 1000).toISOString().replace('T', ' ').substring(0, 19) + ' UTC';
}

function isoDate(d) {
  return d.toISOString().substring(0, 10);
}

// === get_quote ===
if (action === 'get_quote') {
  const symbol = (input.symbol || '').toUpperCase().trim();
  if (!symbol) return [{ json: { error: 'Parameter "symbol" is required (e.g. AAPL, MSFT, TSLA). Use search_symbol if you only know the company name.' } }];

  try {
    const q = await helpers.httpRequest({ method: 'GET', url: API + '/quote?symbol=' + encodeURIComponent(symbol) + '&token=' + token });
    if (q.c === 0 && q.pc === 0) {
      return [{ json: { error: 'No quote data for symbol "' + symbol + '". Symbol may be invalid. Try search_symbol.' } }];
    }
    let out = 'Quote for ' + symbol + ':\n';
    out += '  Current: ' + q.c + '\n';
    const dir = q.d > 0 ? '+' : '';
    out += '  Change: ' + dir + (q.d != null ? q.d.toFixed(2) : '') + ' (' + dir + (q.dp != null ? q.dp.toFixed(2) : '') + '%)\n';
    out += '  Day range: ' + q.l + ' – ' + q.h + '\n';
    out += '  Open: ' + q.o + '\n';
    out += '  Prev close: ' + q.pc + '\n';
    if (q.t) out += '  As of: ' + formatTs(q.t) + '\n';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Finnhub quote failed: ' + err.message } }];
  }

// === get_company_profile ===
} else if (action === 'get_company_profile') {
  const symbol = (input.symbol || '').toUpperCase().trim();
  if (!symbol) return [{ json: { error: 'Parameter "symbol" is required (e.g. AAPL).' } }];

  try {
    const p = await helpers.httpRequest({ method: 'GET', url: API + '/stock/profile2?symbol=' + encodeURIComponent(symbol) + '&token=' + token });
    if (!p || !p.name) {
      return [{ json: { error: 'No profile found for symbol "' + symbol + '".' } }];
    }
    let out = '**' + p.name + '** (' + p.ticker + ')\n';
    if (p.finnhubIndustry) out += 'Industry: ' + p.finnhubIndustry + '\n';
    if (p.exchange) out += 'Exchange: ' + p.exchange + '\n';
    if (p.country) out += 'Country: ' + p.country + '\n';
    if (p.currency) out += 'Currency: ' + p.currency + '\n';
    if (p.marketCapitalization) out += 'Market cap: ' + formatCap(p.marketCapitalization) + ' ' + (p.currency || 'USD') + '\n';
    if (p.shareOutstanding) out += 'Shares outstanding: ' + p.shareOutstanding.toFixed(2) + 'M\n';
    if (p.ipo) out += 'IPO: ' + p.ipo + '\n';
    if (p.weburl) out += 'Web: ' + p.weburl + '\n';
    if (p.logo) out += 'Logo: ' + p.logo + '\n';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Finnhub profile failed: ' + err.message } }];
  }

// === get_company_news ===
} else if (action === 'get_company_news') {
  const symbol = (input.symbol || '').toUpperCase().trim();
  if (!symbol) return [{ json: { error: 'Parameter "symbol" is required.' } }];
  const days = Math.min(parseInt(input.days) || 7, 30);
  const limit = Math.min(parseInt(input.limit) || 5, 15);

  const now = new Date();
  const from = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);

  try {
    const news = await helpers.httpRequest({
      method: 'GET',
      url: API + '/company-news?symbol=' + encodeURIComponent(symbol) + '&from=' + isoDate(from) + '&to=' + isoDate(now) + '&token=' + token
    });
    if (!Array.isArray(news) || news.length === 0) {
      return [{ json: { result: 'No news for ' + symbol + ' in the last ' + days + ' days.' } }];
    }
    const slice = news.slice(0, limit);
    let out = 'Latest news for ' + symbol + ' (' + news.length + ' total, showing ' + slice.length + '):\n\n';
    for (const n of slice) {
      out += '[' + (n.source || 'news') + '] ' + formatTs(n.datetime) + '\n';
      out += '  ' + (n.headline || '') + '\n';
      if (n.summary) out += '  ' + n.summary.substring(0, 200) + (n.summary.length > 200 ? '...' : '') + '\n';
      if (n.url) out += '  ' + n.url + '\n';
      out += '\n';
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Finnhub news failed: ' + err.message } }];
  }

// === search_symbol ===
} else if (action === 'search_symbol') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required (company name or partial ticker).' } }];

  try {
    const data = await helpers.httpRequest({ method: 'GET', url: API + '/search?q=' + encodeURIComponent(query) + '&token=' + token });
    const results = data.result || [];
    if (results.length === 0) return [{ json: { result: 'No symbols found for: ' + query } }];
    const slice = results.slice(0, 10);
    let out = 'Found ' + data.count + ' symbols, showing top ' + slice.length + ':\n\n';
    for (const r of slice) {
      out += (r.displaySymbol || r.symbol) + ' — ' + r.description + ' (' + (r.type || 'unknown') + ')\n';
    }
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Finnhub search failed: ' + err.message } }];
  }

// === get_market_status ===
} else if (action === 'get_market_status') {
  const exchange = (input.exchange || 'US').toUpperCase();
  try {
    const s = await helpers.httpRequest({ method: 'GET', url: API + '/stock/market-status?exchange=' + encodeURIComponent(exchange) + '&token=' + token });
    let out = 'Market: ' + s.exchange + '\n';
    out += 'Status: ' + (s.isOpen ? 'OPEN' : 'CLOSED') + '\n';
    if (s.session) out += 'Session: ' + s.session + '\n';
    if (s.holiday) out += 'Holiday: ' + s.holiday + '\n';
    if (s.timezone) out += 'Timezone: ' + s.timezone + '\n';
    if (s.t) out += 'As of: ' + formatTs(s.t) + '\n';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Finnhub market status failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: get_quote, get_company_profile, get_company_news, search_symbol, get_market_status.' } }];
}
